803	/// Mirrors C's `codeorder` from `lcode.c` for relational binops (`<`, `<=`,
804	/// `>`, `>=`). Emits a comparison opcode (with `k = 1`) followed by an
805	/// `OP_JMP` with offset `NO_JUMP`; the resulting `VJMP` expression carries
806	/// the jump's pc in `e1.u.info` so the surrounding control-flow logic can
807	/// patch it. When one operand is a small-integer literal that fits the
808	/// signed-C field, the immediate forms (`OP_LTI` / `OP_GTI`) are used;
809	/// otherwise both operands are discharged to registers and the register
810	/// form (`OP_LT`) is emitted.
811	fn cg_emit_order(
812	    fs: &mut FuncState,
813	    op: BinOpr,
814	    e1: &mut ExprDesc,
815	    e2: &mut ExprDesc,
816	    line: i32,
817	) -> Result<(), LuaError> {
